## 🪄 Putting It All Together

**Age Mode Switching Example:**  
```jsx name=client/src/pages/MainGame.js
import EmojiCardPicker from '../components/EmojiCardPicker';
import VoiceChatInput from '../components/VoiceChatInput';
import ProgressDashboard from '../components/ProgressDashboard';

export default function MainGame({ user, progress, onEmotionSelect, onAnswer }) {
  return (
    <div>
      <h2>Welcome, {user.name}!</h2>
      {user.age <= 9
        ? <EmojiCardPicker onPick={onEmotionSelect} />
        : <VoiceChatInput onSend={onAnswer} />
      }
      <ProgressDashboard progress={progress} />
    </div>
  );
}
```

