Excellent! Let's build the **backend architecture**, **real-time sync**, **badge system**, **vocab challenges**, and **accessibility enhancements**. Here's a complete implementation:

---

## 📦 Backend Architecture

### 1. **MongoDB Schemas (User, Session, Progress)**

```javascript name=server/models/User.js
const mongoose = require('mongoose');

const UserSchema = new mongoose.Schema({
  _id: mongoose.Schema.Types.ObjectId,
  name: String,
  age: Number,
  role: { type: String, enum: ['player', 'facilitator'] },
  email: String,
  createdAt: { type: Date, default: Date.now },
  totalXP: { type: Number, default: 0 },
  badges: [{ badgeId: String, earnedAt: Date }],
  vocabulary: [{ word: String, learnedAt: Date }],
});

module.exports = mongoose.model('User', UserSchema);
```

```javascript name=server/models/Session.js
const mongoose = require('mongoose');

const SessionSchema = new mongoose.Schema({
  _id: mongoose.Schema.Types.ObjectId,
  roomId: String,
  facilitatorId: mongoose.Schema.Types.ObjectId,
  players: [mongoose.Schema.Types.ObjectId],
  createdAt: { type: Date, default: Date.now },
  completedAt: Date,
  status: { type: String, enum: ['active', 'completed'], default: 'active' },
});

module.exports = mongoose.model('Session', SessionSchema);
```

```javascript name=server/models/Progress.js
const mongoose = require('mongoose');

const ProgressSchema = new mongoose.Schema({
  _id: mongoose.Schema.Types.ObjectId,
  userId: mongoose.Schema.Types.ObjectId,
  sessionId: mongoose.Schema.Types.ObjectId,
  level: String,
  responses: [
    {
      levelName: String,
      question: String,
      answer: String, // chat or emoji
      emotionPicked: { emotion: String, emoji: String },
      voiceInput: String,
      timestamp: Date,
    }
  ],
  xpEarned: { type: Number, default: 0 },
  badgesEarned: [{ badgeId: String, earnedAt: Date }],
  newVocabulary: [String],
  completedLevels: [String],
});

module.exports = mongoose.model('Progress', ProgressSchema);
```

---

### 2. **Express Routes (Save/Fetch Progress)**

```javascript name=server/routes/progress.js
const express = require('express');
const router = express.Router();
const User = require('../models/User');
const Session = require('../models/Session');
const Progress = require('../models/Progress');
const { checkBadges, calculateXP } = require('../utils/gameLogic');

// Create/Join a session
router.post('/session/create', async (req, res) => {
  const { facilitatorId, roomId } = req.body;
  const session = new Session({
    facilitatorId,
    roomId,
    players: [],
  });
  await session.save();
  res.json({ sessionId: session._id, roomId });
});

// Join session
router.post('/session/join', async (req, res) => {
  const { sessionId, userId } = req.body;
  const session = await Session.findByIdAndUpdate(
    sessionId,
    { $push: { players: userId } },
    { new: true }
  );
  res.json(session);
});

// Save level response
router.post('/progress/save-response', async (req, res) => {
  const { userId, sessionId, levelName, response } = req.body;
  // response = { question, answer, emotionPicked, voiceInput, etc }

  let progress = await Progress.findOne({ userId, sessionId });
  if (!progress) {
    progress = new Progress({
      userId,
      sessionId,
      responses: [],
      completedLevels: [],
    });
  }

  // Add response
  progress.responses.push({
    levelName,
    ...response,
    timestamp: new Date(),
  });

  // Calculate XP for this response
  const xpGained = calculateXP(levelName, response);
  progress.xpEarned += xpGained;

  // Check if new badges earned
  const newBadges = checkBadges(progress.xpEarned, progress.completedLevels);
  newBadges.forEach(badge => {
    progress.badgesEarned.push({ badgeId: badge.id, earnedAt: new Date() });
  });

  // Check for new vocab words
  if (response.newVocab) {
    progress.newVocabulary = [...new Set([...progress.newVocabulary, ...response.newVocab])];
  }

  // Mark level as completed
  if (!progress.completedLevels.includes(levelName)) {
    progress.completedLevels.push(levelName);
  }

  await progress.save();

  // Update user's total XP
  await User.findByIdAndUpdate(userId, {
    $inc: { totalXP: xpGained },
    $addToSet: { vocabulary: { $each: response.newVocab || [] } },
  });

  res.json({ progress, xpGained, newBadges });
});

// Get user progress for dashboard
router.get('/progress/:userId/:sessionId', async (req, res) => {
  const { userId, sessionId } = req.params;
  const progress = await Progress.findOne({ userId, sessionId });
  const user = await User.findById(userId);
  res.json({
    xp: progress?.xpEarned || 0,
    totalXP: user?.totalXP || 0,
    badges: progress?.badgesEarned || [],
    vocabulary: user?.vocabulary || [],
    completedLevels: progress?.completedLevels || [],
  });
});

// Get all user's progress across sessions (career view)
router.get('/user/:userId/career', async (req, res) => {
  const { userId } = req.params;
  const user = await User.findById(userId);
  const allProgress = await Progress.find({ userId });

  const totalXP = allProgress.reduce((sum, p) => sum + p.xpEarned, 0);
  const allBadges = [...new Set(allProgress.flatMap(p => p.badgesEarned.map(b => b.badgeId)))];
  const sessions = allProgress.length;

  res.json({
    user: { name: user.name, age: user.age },
    totalXP,
    badges: allBadges,
    sessionsCompleted: sessions,
    vocabulary: user.vocabulary,
  });
});

module.exports = router;
```

---

### 3. **Game Logic Utils (XP Calculation & Badge System)**

```javascript name=server/utils/gameLogic.js
const BADGES = {
  'starter': { id: 'starter', label: 'Starter', xpRequired: 0, iconUrl: '/badges/starter.png' },
  'emotion-explorer': { id: 'emotion-explorer', label: 'Emotion Explorer', xpRequired: 50, iconUrl: '/badges/explorer.png' },
  'mood-master': { id: 'mood-master', label: 'Mood Master', xpRequired: 150, iconUrl: '/badges/master.png' },
  'vocab-champion': { id: 'vocab-champion', label: 'Vocabulary Champion', xpRequired: 30, vocabRequired: 10, iconUrl: '/badges/vocab.png' },
  'perfect-pause': { id: 'perfect-pause', label: 'Perfect Pause Button', xpRequired: 100, iconUrl: '/badges/pause.png' },
};

const VOCAB_CHALLENGES = [
  { id: 'vc1', emotion: 'Joy', words: ['elated', 'content', 'blissful', 'cheerful'] },
  { id: 'vc2', emotion: 'Sadness', words: ['melancholic', 'sorrowful', 'dejected', 'forlorn'] },
  { id: 'vc3', emotion: 'Anger', words: ['furious', 'indignant', 'irate', 'livid'] },
  { id: 'vc4', emotion: 'Fear', words: ['terrified', 'petrified, 'apprehensive', 'anxious'] },
  { id: 'vc5', emotion: 'Disgust', words: ['repulsed', 'revolted', 'nauseated', 'appalled'] },
];

function calculateXP(levelName, response) {
  const baseXP = {
    'WarmUp': 5,
    'EmotionSpotter': 10,
    'MoodScanner': 15,
    'EmotionCycle': 20,
    'EmotionDetective': 25,
    'SkillUpZone': 30,
  };

  let xp = baseXP[levelName] || 10;

  // Bonus for voice/chat answers
  if (response.voiceInput) xp += 5;
  if (response.answer && response.answer.length > 20) xp += 5;

  return xp;
}

function checkBadges(totalXP, completedLevels) {
  const earnedBadges = [];

  if (totalXP >= 0 && !earnedBadges.some(b => b.id === 'starter')) {
    earnedBadges.push(BADGES['starter']);
  }
  if (totalXP >= 50 && !earnedBadges.some(b => b.id === 'emotion-explorer')) {
    earnedBadges.push(BADGES['emotion-explorer']);
  }
  if (totalXP >= 150 && !earnedBadges.some(b => b.id === 'mood-master')) {
    earnedBadges.push(BADGES['mood-master']);
  }
  if (completedLevels.length === 7) {
    earnedBadges.push(BADGES['perfect-pause']);
  }

  return earnedBadges;
}

module.exports = { calculateXP, checkBadges, BADGES, VOCAB_CHALLENGES };
```

---

## 🔌 Socket.io Real-Time Sync

```javascript name=server/socket.js
const socket = require('socket.io');
const Progress = require('./models/Progress');
const User = require('./models/User');

module.exports = (server) => {
  const io = socket(server, { cors: { origin: '*' } });

  io.on('connection', (socket) => {
    // Join room
    socket.on('joinRoom', ({ roomId, user }) => {
      socket.join(roomId);
      socket.to(roomId).emit('userJoined', user);
      console.log(`${user.name} joined room ${roomId}`);
    });

    // Broadcast response to all in room
    socket.on('emotionResponse', async ({ roomId, userId, levelName, response }) => {
      // Save to DB
      const progress = await Progress.findOne({ userId, levelName });
      if (progress) {
        progress.responses.push({ ...response, timestamp: new Date() });
        await progress.save();
      }

      // Broadcast to room
      io.to(roomId).emit('emotionResponseUpdate', {
        userId,
        levelName,
        response,
      });
    });

    // Advance level (facilitator)
    socket.on('advanceLevel', ({ roomId, level }) => {
      io.to(roomId).emit('levelAdvanced', level);
    });

    // XP update (broadcast to room)
    socket.on('xpEarned', ({ roomId, userId, xp, badges }) => {
      io.to(roomId).emit('xpUpdate', { userId, xp, badges });
    });

    // Leave room
    socket.on('leaveRoom', ({ roomId, user }) => {
      socket.leave(roomId);
      io.to(roomId).emit('userLeft', user);
    });

    socket.on('disconnect', () => {
      console.log('User disconnected');
    });
  });
};
```

