## 🎮 Frontend: Real-Time Progress Dashboard with Socket Sync

```jsx name=client/src/components/ProgressDashboard.js
import React, { useEffect, useState } from 'react';

export default function ProgressDashboard({ userId, sessionId, socket, roomId }) {
  const [progress, setProgress] = useState({
    xp: 0,
    badges: [],
    vocabulary: [],
    completedLevels: [],
  });

  useEffect(() => {
    // Fetch initial progress
    fetch(`/api/progress/${userId}/${sessionId}`)
      .then(res => res.json())
      .then(setProgress);

    // Listen for real-time XP updates
    socket.on('xpUpdate', ({ userId: updatedUserId, xp, badges }) => {
      if (updatedUserId === userId) {
        setProgress(prev => ({
          ...prev,
          xp: prev.xp + xp,
          badges: [...new Set([...prev.badges, ...badges])],
        }));
      }
    });

    return () => socket.off('xpUpdate');
  }, [userId, sessionId, socket]);

  return (
    <div style={{ border: '2px solid #68c4af', borderRadius: 10, padding: 20, marginTop: 20 }}>
      <h3 role="heading" aria-level="3">📊 Progress Dashboard</h3>

      {/* XP Display */}
      <div role="region" aria-label="Experience Points">
        <strong>Your XP:</strong>
        <div style={{ fontSize: '2em', fontWeight: 'bold', color: '#ff6b6b' }}>
          {progress.xp}
        </div>
      </div>

      {/* Badges */}
      <div role="region" aria-label="Badges">
        <strong>Badges Earned:</strong>
