import React, { useState } from 'react';
import { VOCAB_CHALLENGES } from '../constants/gameData';

export default function VocabChallenge({ onComplete }) {
  const [currentChallenge, setCurrentChallenge] = useState(0);
  const [selectedWord, setSelectedWord] = useState(null);
  const [score, setScore] = useState(0);

  const challenge = VOCAB_CHALLENGES[currentChallenge];
  const correctAnswer = challenge.words[0]; // First is correct, others shuffled

  function handleWordClick(word) {
    setSelectedWord(word);
    if (word === correctAnswer) {
      setScore(score + 1);
      setTimeout(() => {
        if (currentChallenge < VOCAB_CHALLENGES.length - 1) {
          setCurrentChallenge(currentChallenge + 1);
          setSelectedWord(null);
        } else {
          onComplete(score + 1);
        }
      }, 1000);
    }
  }

  const shuffledWords = [...challenge.words].sort(() => Math.random() - 0.5);

  return (
    <div
      style={{
        border: '2px solid #7c3aed',
        borderRadius: 10,
        padding: 20,
        textAlign: 'center',
      }}
      role="region"
      aria-label="Vocabulary Challenge"
    >
      <h3 role="heading" aria-level="3">🎯 Vocab Challenge</h3>
      <p><strong>Score: {score}</strong></p>
      <p style={{ fontSize: '1.2em', marginBottom: '1em' }}>
        Which word means <strong>{challenge.emotion}</strong>?
      </p>
      <div style={{ display: 'grid', gridTemplateColumns: 'repeat(2, 1fr)', gap: '1em' }}>
        {shuffledWords.map((word, idx) => (
          <button
            key={idx}
            onClick={() => handleWordClick(word)}
            style={{
              padding: '1em',
              fontSize: '1em',
              borderRadius: 8,
              border: '2px solid #7c3aed',
              backgroundColor: selectedWord === word ? (word === correctAnswer ? '#a78bfa' : '#fca5a5') : '#f3e8ff',
              cursor: 'pointer',
              transition: 'all 0.3s',
            }}
            aria-pressed={selectedWord === word}
            disabled={selectedWord !== null}
          >
            {word}
          </button>
        ))}
      </div>
    </div>
  );
}
