export default function VoiceChatInput({ onSend, ariaLabel = "Tell us what you're feeling" }) {
  const [text, setText] = useState('');
  const [listening, setListening] = useState(false);
  let recognition;

  function handleVoice() {
    if (!window.SpeechRecognition && !window.webkitSpeechRecognition) {
      alert('Speech Recognition not supported in your browser.');
      return;
    }
    recognition = new (window.SpeechRecognition || window.webkitSpeechRecognition)();
    recognition.lang = 'en-US';
    recognition.start();
    setListening(true);

    recognition.onresult = event => {
      const transcript = event.results[0][0].transcript;
      setText(transcript);
    };

    recognition.onend = () => setListening(false);

    recognition.onerror = () => {
      setListening(false);
      alert('Speech recognition failed. Please try again or type instead.');
    };
  }

  function handleSend() {
    if (text.trim()) {
      onSend(text);
      setText('');
    }
  }

  return (
    <fieldset
      style={{ border: '2px solid #3b82f6', borderRadius: 10, padding: 20 }}
      role="group"
