## 🚀 Integration Example (Main Game Loop)

```jsx name=client/src/pages/MainGame.js
import React, { useEffect, useState } from 'react';
import EmojiCardPicker from '../components/EmojiCardPicker';
import VoiceChatInput from '../components/VoiceChatInput';
import ProgressDashboard from '../components/ProgressDashboard';
import VocabChallenge from '../components/VocabChallenge';
import io from 'socket.io-client';

export default function MainGame({ user, sessionId, roomId }) {
  const socket = io('http://localhost:3001');
  const [progress, setProgress] = useState(null);
  const [currentLevel, setCurrentLevel] = useState('WarmUp');

  useEffect(() => {
    socket.emit('joinRoom', { roomId, user });

    // Fetch user progress
    fetch(`/api/progress/${user._id}/${sessionId}`)
      .then(res => res.json())
      .then(setProgress);

    return () => socket.disconnect();
  }, [user, sessionId, roomId]);

  async function handleResponse(response) {
    const res = await fetch('/api/progress/save-response', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        userId: user._id,
        sessionId,
        levelName: currentLevel,
        response,
      }),
    });

    const data = await res.json();
    setProgress(prev => ({
      ...prev,
      xp: data.progress.xpEarned,
      badges: [...new Set([...prev.badges, ...data.newBadges])],
    }));

    socket.emit('xpEarned', {
      roomId,
      userId: user._id,
      xp: data.xpGained,
      badges: data.newBadges,
    });
  }

  if (!progress) return <div>Loading...</div>;

  return (
    <main role="main" aria-label="Emotions Quest Game">
      <h1 role="heading" aria-level="1">Emotions Quest 🧠</h1>
      <p>Welcome, <strong>{user.name}</strong> (Age {user.age})!</p>

      {/* Render appropriate input based on age */}
      {user.age <= 9 ? (
        <EmojiCardPicker onPick={card => handleResponse({ emotionPicked: card })} />
      ) : (
        <VoiceChatInput onSend={text => handleResponse({ voiceInput: text, answer: text })} />
      )}

      {/* Vocab Challenge (every 2 levels) */}
      {progress.completedLevels.length % 2 === 0 && progress.completedLevels.length > 0 && (
        <VocabChallenge onComplete={score => handleResponse({ vocabScore: score })} />
      )}

      {/* Real-time progress dashboard */}
      <ProgressDashboard userId={user._id} sessionId={sessionId} socket={socket} roomId={roomId} />
    </main>
  );
}
