## 8️⃣ Updated MainGame Component (Complete Integration)

```jsx name=client/src/pages/MainGame.js
import React, { useEffect, useState } from 'react';
import EmojiCardPicker from '../components/EmojiCardPicker';
import VoiceChatInput from '../components/VoiceChatInput';
import ProgressDashboard from '../components/ProgressDashboard';
import VocabChallenge from '../components/VocabChallenge';
import api from '../services/api';

const LEVELS = [
  'WarmUp',
  'EmotionSpotter',
  'MoodScanner',
  'EmotionCycle',
  'EmotionDetective',
  'SkillUpZone',
  'XPAward',
];

export default function MainGame({
  user,
  session,
  progress,
  socket,
  onCreateSession,
  onFetchProgress,
}) {
  const [currentLevelIdx, setCurrentLevelIdx] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    // Ensure session is created
    if (!session) {
      onCreateSession(`room-${Date.now()}`);
    }
  }, [session, onCreateSession]);

  useEffect(() => {
    // Fetch progress when component mounts
    if (session) {
      onFetchProgress();
    }
  }, [session, onFetchProgress]);

  // Socket listeners
  useEffect(() => {
    if (!socket) return;

    socket.on('levelAdvanced', (newLevel) => {
      setCurrentLevelIdx(newLevel);
    });

    socket.on('emotionResponseUpdate', ({ userId, response }) => {
      console.log(`${userId} responded:`, response);
      onFetchProgress(); // Refresh progress
    });

    return () => {
      socket.off('levelAdvanced');
      socket.off('emotionResponseUpdate');
    };
  }, [socket, onFetchProgress]);

  const currentLevel = LEVELS[currentLevelIdx];
  const token = localStorage.getItem('token');

  async function handleResponse(response) {
    setLoading(true);
    setError('');

    try {
      const data = await fetch('/api/progress/save-response', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          userId: user._id,
          sessionId: session.sessionId,
          levelName: currentLevel,
          response,
        }),
      }).then(res => res.json());

      if (data.error) throw new Error(data.error);

      // Broadcast to room
      socket.emit('emotionResponse', {
        roomId: session.roomId,
        userId: user._id,
        levelName: currentLevel,
        response,
      });

      socket.emit('xpEarned', {
        roomId: session.roomId,
        userId: user._id,
        xp: data.xpGained,
        badges: data.newBadges,
      });

      // Auto advance to next level after 2 seconds
      setTimeout(() => {
        if (currentLevelIdx < LEVELS.length - 1) {
          setCurrentLevelIdx(currentLevelIdx + 1);
          socket.emit('advanceLevel', {
            roomId: session.roomId,
            level: currentLevelIdx + 1,
          });
        }
      }, 2000);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  if (!session || !progress) {
    return <div style={{ textAlign: 'center', marginTop: '5em' }}>Loading game...</div>;
  }

  function renderLevelContent() {
    switch (currentLevel) {
      case 'WarmUp':
        return (
          <div>
            <h3>🧠 Brain's Group Chat</h3>
            <p>What emotion did you feel today?</p>
            {user.age <= 9 ? (
              <EmojiCardPicker
                onPick={card => handleResponse({ emotionPicked: card })}
              />
            ) : (
              <VoiceChatInput
                onSend={text =>
                  handleResponse({ voiceInput: text, answer: text })
                }
              />
            )}
          </div>
        );

      case 'EmotionSpotter':
        return (
          <div>
            <h3>🎯 Emotion Spotter Game</h3>
            <p>What emotion is this? You lose your pencil.</p>
            {user.age <= 9 ? (
              <EmojiCardPicker
                onPick={card => handleResponse({ emotionPicked: card })}
              />
            ) : (
              <VoiceChatInput
                onSend={text =>
                  handleResponse({ voiceInput: text, answer: text })
                }
              />
            )}
          </div>
        );

      case 'MoodScanner':
        return (
          <div>
            <h3>📍 Mood Scanner</h3>
            <p>Close your eyes, take 3 deep breaths. Now, what are you feeling?</p>
            <VoiceChatInput
              onSend={text => handleResponse({ voiceInput: text, answer: text })}
            />
          </div>
        );

      case 'EmotionCycle':
        return (
          <div>
            <h3>🔄 Emotion Cycle</h3>
            <p>
              Situation → Thought → Emotion → Action → Result
            </p>
            <p>Tell us a situation and your thought about it:</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({ voiceInput: text, answer: text, newVocab: ['resilient'] })
              }
            />
          </div>
        );

      case 'EmotionDetective':
        return (
          <div>
            <h3>🔍 Emotion Detective</h3>
            <p>Describe a situation and how you felt:</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({ voiceInput: text, answer: text, newVocab: ['empathetic'] })
              }
            />
          </div>
        );

      case 'SkillUpZone':
        return (
          <div>
            <h3>💪 Skill-Up Zone</h3>
            <p>Practice: Pause for 5 seconds before reacting. Tell us how it felt:</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({ voiceInput: text, answer: text })
              }
            />
          </div>
        );

      case 'XPAward':
        return (
          <div style={{ textAlign: 'center' }}>
            <h3>🏆 XP Award & Cool Down</h3>
            <p>
              Congratulations, <strong>{user.name}</strong>! You completed Emotions
              Quest! 🎉
            </p>
            <p>One new emotion word you learned?</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({
                  voiceInput: text,
                  answer: text,
                  newVocab: [text],
                })
              }
            />
          </div>
        );

      default:
        return <div>Game Complete!</div>;
    }
  }

  return (
    <main role="main" aria-label="Emotions Quest Game">
      <header style={{ padding: '2em', backgroundColor: '#38a169', color: 'white' }}>
        <h1 role="heading" aria-level="1">Emotions Quest 🧠</h1>
        <p>Welcome, <strong>{user.name}</strong> (Age {user.age})!</p>
        <p>
          Level {currentLevelIdx + 1} of {LEVELS.length}
        </p>
      </header>

      <div style={{ padding: '2em', maxWidth: 800, margin: '0 auto' }}>
        {error && (
          <div
            style={{
              backgroundColor: '#fed7d7',
              color: '#c53030',
              padding: '1em',
              borderRadius: 5,
              marginBottom: '1em',
            }}
            role="alert"
          >
            ❌ {error}
          </div>
        )}

        {renderLevelContent()}

        {loading && (
          <p style={{ textAlign: 'center', marginTop: '1em' }}>
            ⏳ Saving your response...
          </p>
        )}

        {/* Vocab Challenge every 2 levels */}
        {progress.completedLevels.length > 0 &&
          progress.completedLevels.length % 2 === 0 && (
            <VocabChallenge
              onComplete={score =>
                handleResponse({ vocabScore: score })
              }
            />
          )}

        {/* Progress Dashboard */}
        <ProgressDashboard
          userId={user._id}
          sessionId={session.sessionId}
          socket={socket}
          roomId={session.roomId}
        />
      </div>
    </main>
  );
}
```

