### 5️⃣ **Updated MainGame with i18n**

```jsx name=client/src/pages/MainGame.js
import React, { useEffect, useState, useContext } from 'react';
import { LanguageContext } from '../context/LanguageContext';
import EmojiCardPicker from '../components/EmojiCardPicker';
import VoiceChatInput from '../components/VoiceChatInput';
import ProgressDashboard from '../components/ProgressDashboard';
import VocabChallenge from '../components/VocabChallenge';
import api from '../services/api';

const LEVELS = [
  'WarmUp',
  'EmotionSpotter',
  'MoodScanner',
  'EmotionCycle',
  'EmotionDetective',
  'SkillUpZone',
  'XPAward',
];

export default function MainGame({
  user,
  session,
  progress,
  socket,
  onCreateSession,
  onFetchProgress,
}) {
  const { t } = useContext(LanguageContext);
  const [currentLevelIdx, setCurrentLevelIdx] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    if (!session) {
      onCreateSession(`room-${Date.now()}`);
    }
  }, [session, onCreateSession]);

  useEffect(() => {
    if (session) {
      onFetchProgress();
    }
  }, [session, onFetchProgress]);

  useEffect(() => {
    if (!socket) return;

    socket.on('levelAdvanced', (newLevel) => {
      setCurrentLevelIdx(newLevel);
    });

    socket.on('emotionResponseUpdate', ({ userId, response }) => {
      console.log(`${userId} responded:`, response);
      onFetchProgress();
    });

    return () => {
      socket.off('levelAdvanced');
      socket.off('emotionResponseUpdate');
    };
  }, [socket, onFetchProgress]);

  const currentLevel = LEVELS[currentLevelIdx];
  const token = localStorage.getItem('token');

  async function handleResponse(response) {
    setLoading(true);
    setError('');

    try {
      const data = await fetch('/api/progress/save-response', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          userId: user._id,
          sessionId: session.sessionId,
          levelName: currentLevel,
          response,
        }),
      }).then(res => res.json());

      if (data.error) throw new Error(data.error);

      socket.emit('emotionResponse', {
        roomId: session.roomId,
        userId: user._id,
        levelName: currentLevel,
        response,
      });

      socket.emit('xpEarned', {
        roomId: session.roomId,
        userId: user._id,
        xp: data.xpGained,
        badges: data.newBadges,
      });

      setTimeout(() => {
        if (currentLevelIdx < LEVELS.length - 1) {
          setCurrentLevelIdx(currentLevelIdx + 1);
          socket.emit('advanceLevel', {
            roomId: session.roomId,
            level: currentLevelIdx + 1,
          });
        }
      }, 2000);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  if (!session || !progress) {
    return <div style={{ textAlign: 'center', marginTop: '5em' }}>{t('auth.loading')}</div>;
  }

  const levelTitles = {
    'WarmUp': t('game.levelWarmUp'),
    'EmotionSpotter': t('game.levelEmotionSpotter'),
    'MoodScanner': t('game.levelMoodScanner'),
    'EmotionCycle': t('game.levelEmotionCycle'),
    'EmotionDetective': t('game.levelEmotionDetective'),
    'SkillUpZone': t('game.levelSkillUpZone'),
    'XPAward': t('game.levelXPAward'),
  };

  function renderLevelContent() {
    switch (currentLevel) {
      case 'WarmUp':
        return (
          <div>
            <h3>🧠 {t('game.levelWarmUp')}</h3>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            {user.age <= 9 ? (
              <EmojiCardPicker
                onPick={card => handleResponse({ emotionPicked: card })}
              />
            ) : (
              <VoiceChatInput
                onSend={text =>
                  handleResponse({ voiceInput: text, answer: text })
                }
              />
            )}
          </div>
        );

      case 'EmotionSpotter':
        return (
          <div>
            <h3>🎯 {t('game.levelEmotionSpotter')}</h3>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            {user.age <= 9 ? (
              <EmojiCardPicker
                onPick={card => handleResponse({ emotionPicked: card })}
              />
            ) : (
              <VoiceChatInput
                onSend={text =>
                  handleResponse({ voiceInput: text, answer: text })
                }
              />
            )}
          </div>
        );

      case 'MoodScanner':
        return (
          <div>
            <h3>📍 {t('game.levelMoodScanner')}</h3>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            <VoiceChatInput
              onSend={text => handleResponse({ voiceInput: text, answer: text })}
            />
          </div>
        );

      case 'EmotionCycle':
        return (
          <div>
            <h3>🔄 {t('game.levelEmotionCycle')}</h3>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({ voiceInput: text, answer: text, newVocab: ['resilient'] })
              }
            />
          </div>
        );

      case 'EmotionDetective':
        return (
          <div>
            <h3>🔍 {t('game.levelEmotionDetective')}</h3>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({ voiceInput: text, answer: text, newVocab: ['empathetic'] })
              }
            />
          </div>
        );

      case 'SkillUpZone':
        return (
          <div>
            <h3>💪 {t('game.levelSkillUpZone')}</h3>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({ voiceInput: text, answer: text })
              }
            />
          </div>
        );

      case 'XPAward':
        return (
          <div style={{ textAlign: 'center' }}>
            <h3>🏆 {t('game.levelXPAward')}</h3>
            <p>
              {t('messages.congratulations')}, <strong>{user.name}</strong>! {t('messages.gameComplete')} 🎉
            </p>
            <p>{t('game.whatEmotionDidYouFeel')}</p>
            <VoiceChatInput
              onSend={text =>
                handleResponse({
                  voiceInput: text,
                  answer: text,
                  newVocab: [text],
                })
              }
            />
          </div>
        );

      default:
        return <div>{t('messages.gameComplete')}</div>;
    }
  }

  return (
    <main role="main" aria-label="Emotions Quest Game">
      <header style={{ padding: '2em', backgroundColor: '#38a169', color: 'white' }}>
        <h1 role="heading" aria-level="1">{t('app.title')} 🧠</h1>
        <p>
          {t('auth.welcomeTitle').split('!')[0]}!, <strong>{user.name}</strong> (Age {user.age})
        </p>
        <p>
          {t('dashboard.levelsCompleted')} {currentLevelIdx + 1} of {LEVELS.length}
        </p>
      </header>

      <div style={{ padding: '2em', maxWidth: 800, margin: '0 auto' }}>
        {error && (
          <div
            style={{
              backgroundColor: '#fed7d7',
              color: '#c53030',
              padding: '1em',
              borderRadius: 5,
              marginBottom: '1em',
            }}
            role="alert"
          >
            ❌ {error}
          </div>
        )}

        {renderLevelContent()}

        {loading && (
          <p style={{ textAlign: 'center', marginTop: '1em' }}>
            {t('messages.savingResponse')}
          </p>
        )}

        {progress.completedLevels.length > 0 &&
          progress.completedLevels.length % 2 === 0 && (
            <VocabChallenge
              onComplete={score =>
                handleResponse({ vocabScore: score })
              }
            />
          )}

        <ProgressDashboard
          userId={user._id}
          sessionId={session.sessionId}
          socket={socket}
          roomId={session.roomId}
        />
      </div>
    </main>
  );
}
