import React, { useState, useContext } from 'react';
import { LanguageContext } from '../context/LanguageContext';

export default function VoiceChatInput({ onSend }) {
  const { t } = useContext(LanguageContext);
  const [text, setText] = useState('');
  const [listening, setListening] = useState(false);
  let recognition;

  function handleVoice() {
    if (!window.SpeechRecognition && !window.webkitSpeechRecognition) {
      alert(t('errors.speechNotSupported'));
      return;
    }
    recognition = new (window.SpeechRecognition || window.webkitSpeechRecognition)();
    recognition.lang = 'en-US';
    recognition.start();
    setListening(true);

    recognition.onresult = event => {
      const transcript = event.results[0][0].transcript;
      setText(transcript);
    };

    recognition.onend = () => setListening(false);

    recognition.onerror = () => {
      setListening(false);
      alert(t('errors.speechFailed'));
    };
  }

  function handleSend() {
    if (text.trim()) {
      onSend(text);
      setText('');
    }
  }

  return (
    <fieldset
      style={{ border: '2px solid #3b82f6', borderRadius: 10, padding: 20 }}
      role="group"
      aria-labelledby="voice-chat-label"
    >
      <legend id="voice-chat-label" style={{ fontSize: '1.1em', fontWeight: 'bold' }}>
        {t('game.tellUs')}
      </legend>
      <div style={{ marginTop: '1em' }}>
        <button
          onClick={handleVoice}
          disabled={listening}
          aria-pressed={listening}
          aria-label={listening ? t('game.listening') : t('game.speak')}
          style={{
            padding: '0.75em 1.5em',
            fontSize: '1em',
            marginRight: '1em',
            backgroundColor: listening ? '#ef4444' : '#3b82f6',
            color: 'white',
            border: 'none',
            borderRadius: 5,
            cursor: listening ? 'default' : 'pointer',
          }}
        >
          {listening ? `🎤 ${t('game.listening')}` : `🎤 ${t('game.speak')}`}
        </button>

        <input
          type="text"
          placeholder={t('game.typeHere')}
          value={text}
          onChange={e => setText(e.target.value)}
          onKeyPress={e => e.key === 'Enter' && handleSend()}
          aria-label={t('game.typeHere')}
          style={{
            padding: '0.75em',
            fontSize: '1em',
            borderRadius: 5,
            border: '1px solid #ccc',
            width: '60%',
            marginRight: '0.5em',
          }}
        />

        <button
          onClick={handleSend}
          disabled={!text}
          aria-label={t('game.send')}
          style={{
            padding: '0.75em 1.5em',
            fontSize: '1em',
            backgroundColor: text ? '#10b981' : '#ccc',
            color: 'white',
            border: 'none',
            borderRadius: 5,
            cursor: text ? 'pointer' : 'default',
          }}
        >
          {t('game.send')}
        </button>
      </div>
    </fieldset>
  );
}
