import React, { useEffect, useState, useContext } from 'react';
import { LanguageContext } from '../context/LanguageContext';

export default function ProgressDashboard({ userId, sessionId, socket, roomId }) {
  const { t } = useContext(LanguageContext);
  const [progress, setProgress] = useState({
    xp: 0,
    badges: [],
    vocabulary: [],
    completedLevels: [],
  });

  useEffect(() => {
    fetch(`/api/progress/${userId}/${sessionId}`)
      .then(res => res.json())
      .then(setProgress);

    socket.on('xpUpdate', ({ userId: updatedUserId, xp, badges }) => {
      if (updatedUserId === userId) {
        setProgress(prev => ({
          ...prev,
          xp: prev.xp + xp,
          badges: [...new Set([...prev.badges, ...badges])],
        }));
      }
    });

    return () => socket.off('xpUpdate');
  }, [userId, sessionId, socket]);

  return (
    <div style={{ border: '2px solid #68c4af', borderRadius: 10, padding: 20, marginTop: 20 }}>
      <h3 role="heading" aria-level="3">{t('dashboard.progressDashboard')}</h3>

      <div role="region" aria-label={t('dashboard.yourXP')}>
        <strong>{t('dashboard.yourXP')}</strong>
        <div style={{ fontSize: '2em', fontWeight: 'bold', color: '#ff6b6b' }}>
          {progress.xp}
        </div>
      </div>

      <div role="region" aria-label={t('dashboard.badgesEarned')} style={{ marginTop: '1em' }}>
        <strong>{t('dashboard.badgesEarned')}</strong>
        <div style={{ display: 'flex', gap: '1em', marginTop: '0.5em', flexWrap: 'wrap' }}>
          {progress.badges.length === 0 ? (
            <span>{t('dashboard.noBadgesYet')}</span>
          ) : (
            progress.badges.map((badge, idx) => (
              <div
                key={idx}
                style={{
                  textAlign: 'center',
                  padding: '1em',
                  border: '1px solid gold',
                  borderRadius: 10,
                  backgroundColor: '#fffacd',
                }}
                role="article"
                aria-label={`Badge: ${badge.label}`}
              >
                <img src={badge.iconUrl} alt={badge.label} width={40} />
                <p>{badge.label}</p>
              </div>
            ))
          )}
        </div>
      </div>

      <div role="region" aria-label={t('dashboard.vocabularyLearned')} style={{ marginTop: '1em' }}>
        <strong>{t('dashboard.vocabularyLearned')}</strong>
        <ul style={{ listStyleType: 'none', paddingLeft: 0 }}>
          {progress.vocabulary.map((word, i) => (
