```javascript name=server/routes/progress.js
const express = require('express');
const router = express.Router();
const User = require('../models/User');
const Progress = require('../models/Progress');
const { calculateXP, checkBadges } = require('../utils/gameLogic');
const authMiddleware = require('../middleware/auth');

router.post('/session/create', authMiddleware, async (req, res) => {
  try {
    const { facilitatorId, roomId } = req.body;
    const Session = require('../models/Session');
    const session = new Session({
      facilitatorId,
      roomId,
      players: [],
    });
    await session.save();
    res.json({ success: true, sessionId: session._id, roomId });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

router.post('/progress/save-response', authMiddleware, async (req, res) => {
  try {
    const { userId, sessionId, levelName, answer, isCorrect, isInclusive } = req.body;

    let progress = await Progress.findOne({ userId, sessionId });
    if (!progress) {
      progress = new Progress({
        userId,
        sessionId,
        responses: [],
        completedLevels: [],
        xpEarned: 0,
        badgesEarned: [],
      });
    }

    progress.responses.push({
      levelName,
      question: req.body.question,
      answer,
      timestamp: new Date(),
    });

    const xpGained = calculateXP(levelName, isCorrect, isInclusive);
    progress.xpEarned += xpGained;

    const newBadges = checkBadges(progress.xpEarned, progress.completedLevels);
    newBadges.forEach(badge => {
      if (!progress.badgesEarned.some(b => b.badgeId === badge.id)) {
        progress.badgesEarned.push({ badgeId: badge.id, earnedAt: new Date() });
      }
    });

    if (!progress.completedLevels.includes(levelName)) {
      progress.completedLevels.push(levelName);
    }

    await progress.save();
    await User.findByIdAndUpdate(userId, { $inc: { totalXP: xpGained } });

    res.json({
      success: true,
      progress,
      xpGained,
      newBadges,
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

router.get('/progress/:userId/:sessionId', authMiddleware, async (req, res) => {
  try {
    const { userId, sessionId } = req.params;
    const progress = await Progress.findOne({ userId, sessionId });
    const user = await User.findById(userId);

    res.json({
      xp: progress?.xpEarned || 0,
      totalXP: user?.totalXP || 0,
      badges: progress?.badgesEarned || [],
      completedLevels: progress?.completedLevels || [],
    });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

router.post('/reflection/save', authMiddleware, async (req, res) => {
  try {
    const { userId, sessionId, reflection } = req.body;
    const progress = await Progress.findOneAndUpdate(
      { userId, sessionId },
      { finalReflection: reflection },
      { new: true }
    );
    res.json({ success: true, progress });
  } catch (err) {
    res.status(500).json({ error: err.message });
  }
});

module.exports = router;
