  io.on('connection', (socket) => {
    socket.on('joinRoom', ({ roomId, user }) => {
      socket.join(roomId);
      io.to(roomId).emit('userJoined', user);
    });

    socket.on('advanceLevel', ({ roomId, level }) => {
      io.to(roomId).emit('levelAdvanced', level);
    });

    socket.on('response', ({ roomId, user, response }) => {
      io.to(roomId).emit('responseUpdate', { user, response });
    });

    socket.on('disconnect', () => {
      console.log('User disconnected');
    });
  });
};
