import React, { useState, useContext } from 'react';
import { GameContext } from '../context/GameContext';
import { LanguageContext } from '../context/LanguageContext';
import TheoryPopUp from './TheoryPopUp';

const STATEMENTS = [
  { text: "Boys don't cry.", isStereotype: true, theory: 'socialLearning' },
  { text: "Girls can be leaders.", isStereotype: false, theory: 'genderSchema' },
  { text: "Only boys can play football.", isStereotype: true, theory: 'cognitiveBehavior' },
  { text: "Everyone deserves respect.", isStereotype: false, theory: 'socialIdentity' },
];

export default function Level1({ userAge, onComplete }) {
  const [current, setCurrent] = useState(0);
  const [showPopUp, setShowPopUp] = useState(null);
  const { state, addXP } = useContext(GameContext);
  const { t } = useContext(LanguageContext);

  const statement = STATEMENTS[current];

  function handleAnswer(isStereotype) {
    const isCorrect = isStereotype === statement.isStereotype;
    const xpGain = isCorrect ? 10 : 0;
    const isInclusive = isCorrect;

    addXP(xpGain + (isInclusive ? 10 : 0));

    if (!isCorrect) {
      setShowPopUp(statement.theory);
      setTimeout(() => {
        if (current < STATEMENTS.length - 1) setCurrent(current + 1);
        else onComplete();
        setShowPopUp(null);
      }, 3000);
    } else {
      if (current < STATEMENTS.length - 1) setCurrent(current + 1);
      else onComplete();
    }
  }

  return (
    <div style={{ padding: '2em', maxWidth: 600, margin: '0 auto' }}>
      <h2>🎯 {t('game.level1Title')}</h2>
      <p style={{ fontSize: '1.2em', fontWeight: 'bold', marginBottom: '2em' }}>{statement.text}</p>

      <div style={{ display: 'flex', gap: '1em' }}>
        <button onClick={() => handleAnswer(true)} style={{ flex: 1, padding: '1em', backgroundColor: '#ef4444', color: 'white', border: 'none', borderRadius: 5, cursor: 'pointer', fontSize: '1em' }}>
          {t('game.stereotype')}
        </button>
        <button onClick={() => handleAnswer(false)} style={{ flex: 1, padding: '1em', backgroundColor: '#10b981', color: 'white', border: 'none', borderRadius: 5, cursor: 'pointer', fontSize: '1em' }}>
          {t('game.fairIdea')}
        </button>
      </div>

      <p style={{ textAlign: 'center', marginTop: '2em', fontSize: '0.9em', color: '#666' }}>
        {current + 1} / {STATEMENTS.length}
      </p>

      {showPopUp && <TheoryPopUp theory={showPopUp} />}
    </div>
  );
}
