];

export default function Level4({ userAge, onComplete }) {
  const [selected, setSelected] = useState([]);
  const { addXP } = useContext(GameContext);
  const { t } = useContext(LanguageContext);

  function toggleRule(idx) {
    if (selected.includes(idx)) {
      setSelected(selected.filter(i => i !== idx));
    } else {
      setSelected([...selected, idx]);
    }
  }

  function handleComplete() {
    addXP(selected.length * 15);

    let badge = '';
    if (selected.length === 4) badge = 'Equality Champion 🏆';
    else if (selected.length === 3) badge = 'Respect Builder 🌟';
    else badge = 'Growing Ally 🌱';

    onComplete({ badge, reflection: true });
