```jsx name=client/src/pages/MainGame.js
import React, { useState, useContext } from 'react';
import Level1 from '../components/Level1';
import Level2 from '../components/Level2';
import Level3 from '../components/Level3';
import Level4 from '../components/Level4';
import ReflectionScreen from '../components/ReflectionScreen';
import { GameContext } from '../context/GameContext';
import { LanguageContext } from '../context/LanguageContext';

export default function MainGame({ user }) {
  const [currentLevel, setCurrentLevel] = useState(0);
  const [showReflection, setShowReflection] = useState(false);
  const [finalBadge, setFinalBadge] = useState('');
  const { state } = useContext(GameContext);
  const { t } = useContext(LanguageContext);

  const levels = [
    { component: Level1, title: t('game.level1Title') },
    { component: Level2, title: t('game.level2Title') },
    { component: Level3, title: t('game.level3Title') },
    { component: Level4, title: t('game.level4Title') },
  ];

  function handleLevelComplete(data) {
    if (data?.reflection) {
      setFinalBadge(data.badge);
      setShowReflection(true);
    } else if (currentLevel < levels.length - 1) {
      setCurrentLevel(currentLevel + 1);
    } else {
      setShowReflection(true);
    }
  }

  function handleReflectionSubmit(reflection) {
    fetch('/api/reflection/save', {
      method: 'POST',
      headers: {
        'Content-Type': 'application/json',
        'Authorization': `Bearer ${localStorage.getItem('token')}`,
      },
      body: JSON.stringify({
        userId: user._id,
        reflection,
      }),
    });
    alert('Certificate downloaded! You completed Equality Quest! 🏆');
  }

  if (showReflection) {
    return <ReflectionScreen badge={finalBadge} onSubmit={handleReflectionSubmit} />;
  }

  const CurrentLevel = levels[currentLevel].component;

  return (
    <main style={{ backgroundColor: '#f9f9f9', minHeight: '100vh', paddingTop: '2em' }}>
      <header style={{ textAlign: 'center', marginBottom: '2em' }}>
        <h1>{t('app.title')} 🌈</h1>
        <p>Level {currentLevel + 1} / {levels.length}</p>
        <div style={{ fontSize: '1.5em', marginTop: '1em' }}>
          XP: {state.xp} | Badges: {state.badges.length}
        </div>
      </header>

      <CurrentLevel
        userAge={user.age}
        onComplete={handleLevelComplete}
      />

      <style>{`
        @keyframes fadeIn {
          from { opacity: 0; }
          to { opacity: 1; }
        }
      `}</style>
    </main>
  );
}
