import React, { useState, useEffect } from 'react';

const levels = [
  'WarmUp', 'EmotionSpotter', 'MoodScanner', 'EmotionCycle', 'EmotionDetective', 'SkillUpZone', 'XPAward'
];

function getModeByAge(age) {
  if (age <= 9) return "simple";
  else return "advanced";
}

export default function GameBoard({ user, socket, roomId }) {
  const [currentLevel, setCurrentLevel] = useState(0);
  const [responses, setResponses] = useState([]);

  useEffect(() => {
    socket.on('levelAdvanced', setCurrentLevel);
    socket.on('emotionResponseUpdate', ({ user, response }) => {
      setResponses(prev => [...prev, { user, response }]);
    });
    return () => {
      socket.off('levelAdvanced');
      socket.off('emotionResponseUpdate');
    };
  }, [socket]);

  const mode = getModeByAge(user.age);

  function handleLevelAdvance() {
    socket.emit('advanceLevel', { roomId, level: currentLevel + 1 });
  }

  function handleResponse(response) {
    socket.emit('emotionResponse', { roomId, user, response });
  }

  // Each level would have its own small component. Here's one example:
  function WarmUp() {
    return (
      <div>
        <h3>Brain's Group Chat</h3>
        <p>What emotion did you feel today?</p>
        <input onBlur={e => handleResponse({ level: 'WarmUp', emotion: e.target.value })} />
        <p>Can you show that emotion with your face?</p>
        {/* Show emoji picker or ask for webcam snap for advanced mode */}
        <button onClick={handleLevelAdvance}>Next Level</button>
      </div>
    );
  }

  // ...other levels: EmotionSpotter, MoodScanner, etc, following the module outline.
  // For each, use age-specific instructions ("Explain why?" for advanced; "Raise card" for simple).
  // For multiuser, display all users' responses in a board.

  function renderLevel() {
    switch (levels[currentLevel]) {
      case 'WarmUp': return <WarmUp />;
      // ...implement other levels
      default: return <div>Game Complete!</div>;
    }
  }

  return (
    <div>
      <h2>Emotions Quest - {user.name} ({user.role})</h2>
      <div>
        {renderLevel()}
      </div>
      <div>
        <h4>Responses:</h4>
        {responses.map((r, idx) => (
          <div key={idx}>{r.user.name}: {JSON.stringify(r.response)}</div>
        ))}
      </div>
    </div>
  );
}

