import React, { useEffect, useState } from 'react';
import EmojiCardPicker from '../components/EmojiCardPicker';
import VoiceChatInput from '../components/VoiceChatInput';
import ProgressDashboard from '../components/ProgressDashboard';
import VocabChallenge from '../components/VocabChallenge';
import io from 'socket.io-client';

export default function MainGame({ user, sessionId, roomId }) {
  const socket = io('http://localhost:3001');
  const [progress, setProgress] = useState(null);
  const [currentLevel, setCurrentLevel] = useState('WarmUp');

  useEffect(() => {
    socket.emit('joinRoom', { roomId, user });

    // Fetch user progress
    fetch(`/api/progress/${user._id}/${sessionId}`)
      .then(res => res.json())
      .then(setProgress);

    return () => socket.disconnect();
  }, [user, sessionId, roomId]);

  async function handleResponse(response) {
    const res = await fetch('/api/progress/save-response', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({
        userId: user._id,
        sessionId,
        levelName: currentLevel,
        response,
      }),
    });

    const data = await res.json();
    setProgress(prev => ({
      ...prev,
      xp: data.progress.xpEarned,
      badges: [...new Set([...prev.badges, ...data.newBadges])],
    }));

    socket.emit('xpEarned', {
      roomId,
      userId: user._id,
      xp: data.xpGained,
      badges: data.newBadges,
    });
  }

  if (!progress) return <div>Loading...</div>;

  return (
    <main role="main" aria-label="Emotions Quest Game">
      <h1 role="heading" aria-level="1">Emotions Quest 🧠</h1>
      <p>Welcome, <strong>{user.name}</strong> (Age {user.age})!</p>

      {/* Render appropriate input based on age */}
      {user.age <= 9 ? (
        <EmojiCardPicker onPick={card => handleResponse({ emotionPicked: card })} />
      ) : (
        <VoiceChatInput onSend={text => handleResponse({ voiceInput: text, answer: text })} />
      )}

      {/* Vocab Challenge (every 2 levels) */}
      {progress.completedLevels.length % 2 === 0 && progress.completedLevels.length > 0 && (
        <VocabChallenge onComplete={score => handleResponse({ vocabScore: score })} />
      )}

      {/* Real-time progress dashboard */}
      <ProgressDashboard userId={user._id} sessionId={sessionId} socket={socket} roomId={roomId} />
    </main>
  );
}

import React, { useEffect, useState } from 'react';
import EmojiCardPicker from '../components/EmojiCardPicker';
import VoiceChatInput from '../components/VoiceChatInput';
import ProgressDashboard from '../components/ProgressDashboard';
import VocabChallenge from '../components/VocabChallenge';
import api from '../services/api';

const LEVELS = [
  'WarmUp',
  'EmotionSpotter',
  'MoodScanner',
  'EmotionCycle',
  'EmotionDetective',
  'SkillUpZone',
  'XPAward',
];

export default function MainGame({
  user,
  session,
  progress,
  socket,
  onCreateSession,
  onFetchProgress,
}) {
  const [currentLevelIdx, setCurrentLevelIdx] = useState(0);
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  useEffect(() => {
    // Ensure session is created
    if (!session) {
      onCreateSession(`room-${Date.now()}`);
    }
  }, [session, onCreateSession]);

  useEffect(() => {
    // Fetch progress when component mounts
    if (session) {
      onFetchProgress();
    }
  }, [session, onFetchProgress]);

  // Socket listeners
  useEffect(() => {
    if (!socket) return;

    socket.on('levelAdvanced', (newLevel) => {
      setCurrentLevelIdx(newLevel);
    });

    socket.on('emotionResponseUpdate', ({ userId, response }) => {
      console.log(`${userId} responded:`, response);
      onFetchProgress(); // Refresh progress
    });

    return () => {
      socket.off('levelAdvanced');
      socket.off('emotionResponseUpdate');
    };
  }, [socket, onFetchProgress]);

  const currentLevel = LEVELS[currentLevelIdx];
  const token = localStorage.getItem('token');

  async function handleResponse(response) {
    setLoading(true);
    setError('');

    try {
      const data = await fetch('/api/progress/save-response', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'Authorization': `Bearer ${token}`,
        },
        body: JSON.stringify({
          userId: user._id,
          sessionId: session.sessionId,
          levelName: currentLevel,
          response,
        }),
      }).then(res => res.json());

      if (data.error) throw new Error(data.error);

      // Broadcast to room
      socket.emit('emotionResponse', {
        roomId: session.roomId,
        userId: user._id,
        levelName: currentLevel,
        response,
      });

      socket.emit('xpEarned', {
        roomId: session.roomId,
        userId: user._id,
        xp: data.xpGained,
        badges: data.newBadges,
      });

      // Auto advance to next level after 2 seconds
      setTimeout(() => {
        if (currentLevelIdx < LEVELS.length - 1) {
          setCurrentLevelIdx(currentLevelIdx + 1);
          socket.emit('advanceLevel', {
            roomId: session.roomId,
            level: currentLevelIdx + 1,
          });
        }
      }, 2000);
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  }

  if (!session || !progress) {
    return <div style={{ textAlign: 'center', marginTop: '5em' }}>Loading game...</div>;
  }

  function renderLevelContent() {
    switch (currentLevel) {
      case 'WarmUp':
        return (
          <div>
            <h3>🧠 Brain's Group Chat</h3>
            <p>What emotion did you feel today?</p>
            {user.age <= 9 ? (
              <EmojiCardPicker
                onPick={card => handleResponse({ emotionPicked: card })}
              />
            ) : (
              <VoiceChatInput
                onSend={text =>
                  handleResponse({ voiceInput: text, answer: text })
                }
              />
            )}
          </div>
        );

      case 'EmotionSpotter':
        return (
          <div>
            <h3>🎯 Emotion Spotter Game</h3>
            <p>What emotion is this? You lose your pencil.</p>
            {user.age <= 9 ? (
              <EmojiCardPicker
                onPick={card => handleResponse({ emotionPicked: card })}
              />
            ) : (
              <VoiceChatInput
                onSend={text =>
                  handleResponse({ voiceInput: text, answer: text })
                }
              />
            )}
          </div>
        );

      case 'MoodScanner':
        return (
          <div>
            <h3>📍 Mood Scanner</h3>
            <p>Close your eyes, take 3 deep breaths. Now, what are you feeling?</p>
            <VoiceChatInput
              onSend={text => handleResponse({ voiceInput: text, answer: text })}
            />
          </div>
        );

      case 'EmotionCycle':
        return (
          <div>
            <h3>🔄 Emotion Cycle</h3>
            <p>
              Situation → Thought → Emotion → Action → Result
            </p>
            <p>Tell us a situation and your thought about it:</p>
            <VoiceChatInput
              onSend={text =>
