const BADGES = {
  'starter': { id: 'starter', label: 'Starter', xpRequired: 0, iconUrl: '/badges/starter.png' },
  'emotion-explorer': { id: 'emotion-explorer', label: 'Emotion Explorer', xpRequired: 50, iconUrl: '/badges/explorer.png' },
  'mood-master': { id: 'mood-master', label: 'Mood Master', xpRequired: 150, iconUrl: '/badges/master.png' },
  'vocab-champion': { id: 'vocab-champion', label: 'Vocabulary Champion', xpRequired: 30, vocabRequired: 10, iconUrl: '/badges/vocab.png' },
  'perfect-pause': { id: 'perfect-pause', label: 'Perfect Pause Button', xpRequired: 100, iconUrl: '/badges/pause.png' },
};

const VOCAB_CHALLENGES = [
  { id: 'vc1', emotion: 'Joy', words: ['elated', 'content', 'blissful', 'cheerful'] },
  { id: 'vc2', emotion: 'Sadness', words: ['melancholic', 'sorrowful', 'dejected', 'forlorn'] },
  { id: 'vc3', emotion: 'Anger', words: ['furious', 'indignant', 'irate', 'livid'] },
  { id: 'vc4', emotion: 'Fear', words: ['terrified', 'petrified, 'apprehensive', 'anxious'] },
  { id: 'vc5', emotion: 'Disgust', words: ['repulsed', 'revolted', 'nauseated', 'appalled'] },
];

function calculateXP(levelName, response) {
  const baseXP = {
    'WarmUp': 5,
    'EmotionSpotter': 10,
    'MoodScanner': 15,
    'EmotionCycle': 20,
    'EmotionDetective': 25,
    'SkillUpZone': 30,
  };

  let xp = baseXP[levelName] || 10;

  // Bonus for voice/chat answers
  if (response.voiceInput) xp += 5;
  if (response.answer && response.answer.length > 20) xp += 5;

  return xp;
}

function checkBadges(totalXP, completedLevels) {
  const earnedBadges = [];

  if (totalXP >= 0 && !earnedBadges.some(b => b.id === 'starter')) {
    earnedBadges.push(BADGES['starter']);
  }
  if (totalXP >= 50 && !earnedBadges.some(b => b.id === 'emotion-explorer')) {
    earnedBadges.push(BADGES['emotion-explorer']);
  }
  if (totalXP >= 150 && !earnedBadges.some(b => b.id === 'mood-master')) {
    earnedBadges.push(BADGES['mood-master']);
  }
  if (completedLevels.length === 7) {
    earnedBadges.push(BADGES['perfect-pause']);
  }

  return earnedBadges;
}

module.exports = { calculateXP, checkBadges, BADGES, VOCAB_CHALLENGES };

