  error: null,
};

function gameReducer(state, action) {
  switch (action.type) {
    case 'LOGIN_START':
      return { ...state, loading: true, error: null };
    case 'LOGIN_SUCCESS':
      return {
        ...state,
        user: action.payload.user,
        token: action.payload.token,
        loading: false,
      };
    case 'LOGIN_FAIL':
      return { ...state, error: action.payload, loading: false };
    case 'CREATE_SESSION':
      return { ...state, session: action.payload };
    case 'SET_PROGRESS':
      return { ...state, progress: action.payload };
    case 'SET_LEVEL':
      return { ...state, currentLevel: action.payload };
    case 'LOGOUT':
      return initialState;
    default:
      return state;
  }
}

export function GameProvider({ children }) {
  const [state, dispatch] = useReducer(gameReducer, initialState);

  const login = useCallback(async (name, age, role, email) => {
    dispatch({ type: 'LOGIN_START' });
    try {
      const data = await api.login({ name, age, role, email });
      localStorage.setItem('token', data.token);
      dispatch({
        type: 'LOGIN_SUCCESS',
        payload: { user: data.user, token: data.token },
      });
      return data;
    } catch (err) {
      dispatch({ type: 'LOGIN_FAIL', payload: err.message });
      throw err;
    }
  }, []);

  const createSession = useCallback(async (roomId) => {
    try {
      const data = await api.createSession(state.user._id, roomId);
      dispatch({ type: 'CREATE_SESSION', payload: data });
      return data;
    } catch (err) {
      dispatch({ type: 'LOGIN_FAIL', payload: err.message });
    }
  }, [state.user]);

  const fetchProgress = useCallback(async () => {
    try {
      const data = await api.getProgress(state.user._id, state.session.sessionId);
      dispatch({ type: 'SET_PROGRESS', payload: data });
    } catch (err) {
      dispatch({ type: 'LOGIN_FAIL', payload: err.message });
    }
  }, [state.user, state.session]);

  const logout = useCallback(() => {
    localStorage.removeItem('token');
    dispatch({ type: 'LOGOUT' });
  }, []);

  return (
    <GameContext.Provider value={{ state, login, createSession, fetchProgress, logout }}>
      {children}
    </GameContext.Provider>
  );
}

import React, { createContext, useReducer, useCallback } from 'react';

export const GameContext = createContext();

const initialState = {
  user: null,
  token: null,
  session: null,
  currentLevel: 0,
  xp: 0,
  badges: [],
  loading: false,
  error: null,
};

function gameReducer(state, action) {
  switch (action.type) {
    case 'LOGIN_SUCCESS':
      return { ...state, user: action.payload.user, token: action.payload.token };
    case 'SET_LEVEL':
      return { ...state, currentLevel: action.payload };
    case 'ADD_XP':
      return { ...state, xp: state.xp + action.payload };
    case 'ADD_BADGE':
      return { ...state, badges: [...state.badges, action.payload] };
    case 'LOGOUT':
      return initialState;
    default:
      return state;
  }
}

export function GameProvider({ children }) {
  const [state, dispatch] = useReducer(gameReducer, initialState);

  const login = useCallback(async (name, age, role, email) => {
    const res = await fetch('/api/auth/login', {
      method: 'POST',
      headers: { 'Content-Type': 'application/json' },
      body: JSON.stringify({ name, age, role, email }),
    });
    const data = await res.json();
    localStorage.setItem('token', data.token);
    dispatch({
      type: 'LOGIN_SUCCESS',
      payload: { user: data.user, token: data.token },
    });
  }, []);

  const addXP = useCallback((amount) => {
    dispatch({ type: 'ADD_XP', payload: amount });
  }, []);

  const addBadge = useCallback((badge) => {
    dispatch({ type: 'ADD_BADGE', payload: badge });
  }, []);

  const logout = useCallback(() => {
    localStorage.removeItem('token');
    dispatch({ type: 'LOGOUT' });
  }, []);

  return (
    <GameContext.Provider value={{ state, login, addXP, addBadge, logout, dispatch }}>
      {children}
    </GameContext.Provider>
  );
}

