import React, { useState, useContext } from 'react';
import { GameContext } from '../context/GameContext';
import { LanguageContext } from '../context/LanguageContext';

const RULES = [
  { rule: 'Equal speaking turns', emoji: '🗣️' },
  { rule: 'Shared chores', emoji: '🧹' },
  { rule: 'No teasing rule', emoji: '🤐' },
  { rule: 'Kind language', emoji: '💚' },
];

export default function Level4({ userAge, onComplete }) {
  const [selected, setSelected] = useState([]);
  const { addXP } = useContext(GameContext);
  const { t } = useContext(LanguageContext);

  function toggleRule(idx) {
    if (selected.includes(idx)) {
      setSelected(selected.filter(i => i !== idx));
    } else {
      setSelected([...selected, idx]);
    }
  }

  function handleComplete() {
    addXP(selected.length * 15);

    let badge = '';
    if (selected.length === 4) badge = 'Equality Champion 🏆';
    else if (selected.length === 3) badge = 'Respect Builder 🌟';
    else badge = 'Growing Ally 🌱';

    onComplete({ badge, reflection: true });
  }

  return (
    <div style={{ padding: '2em', maxWidth: 600, margin: '0 auto' }}>
      <h2>🏠 {t('game.level4Title')}</h2>
      <p>Select the classroom rules that create fairness:</p>

      <div style={{ display: 'grid', gap: '1em', marginBottom: '2em' }}>
        {RULES.map((item, idx) => (
          <button
            key={idx}
            onClick={() => toggleRule(idx)}
            style={{
              padding: '1em',
              backgroundColor: selected.includes(idx) ? '#a8d8f0' : '#f0f0f0',
              border: selected.includes(idx) ? '2px solid #7c3aed' : '2px solid #ccc',
              borderRadius: 5,
              cursor: 'pointer',
              fontSize: '1em',
              fontWeight: 'bold',
              textAlign: 'left',
            }}
